import{_ as a,o as e,c as i,a2 as l}from"./chunks/framework.DZrHScmQ.js";const p=JSON.parse('{"title":"AI Tooling Practices","description":"","frontmatter":{},"headers":[],"relativePath":"ai-native/tooling/index.md","filePath":"ai-native/tooling/README.md"}'),d={name:"ai-native/tooling/index.md"};function o(r,t,n,c,h,s){return e(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="ai-tooling-practices" tabindex="-1">AI Tooling Practices <a class="header-anchor" href="#ai-tooling-practices" aria-label="Permalink to &quot;AI Tooling Practices&quot;">​</a></h1><p><strong>状态：Draft</strong></p><p>本目录记录具体 Agent 宿主和外部系统 CLI 的采用方式。它回答“这个工具如何配置和使用”，但不替代组织级原则。</p><h2 id="当前指南" tabindex="-1">当前指南 <a class="header-anchor" href="#当前指南" aria-label="Permalink to &quot;当前指南&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具</th><th>主要角色</th><th>指南</th></tr></thead><tbody><tr><td>Codex</td><td>软件工程 Agent 与可扩展工作台</td><td><a href="./codex.html">Codex Practices</a></td></tr><tr><td>Claude Code</td><td>终端型软件工程 Agent</td><td><a href="./claude-code.html">Claude Code Practices</a></td></tr><tr><td>Claude Auth</td><td>账号、OAuth profile 与 API token 的使用边界</td><td><a href="./claude-auth.html">Claude Auth</a></td></tr><tr><td>OpenClaw</td><td>飞书中的常驻协作 Agent 与任务路由层</td><td><a href="./openclaw.html">OpenClaw Practices</a></td></tr><tr><td>Feishu CLI</td><td>Agent 访问飞书协作系统的结构化接口</td><td><a href="./feishu-cli.html">Feishu CLI Practices</a></td></tr></tbody></table><h2 id="跨工具共同做法" tabindex="-1">跨工具共同做法 <a class="header-anchor" href="#跨工具共同做法" aria-label="Permalink to &quot;跨工具共同做法&quot;">​</a></h2><ol><li>用目标、上下文、约束和完成条件定义任务。</li><li>复杂任务先探索和计划，小改动直接执行。</li><li>持久指令保持短小，只写工具无法从代码推断的内容。</li><li>重复工作进入 Skill，强制动作进入 Hook 或 CI。</li><li>外部系统采用最小权限、结构化输出和显式身份。</li><li>写操作遵循“读取、预演、确认、执行、回读”。</li><li>Agent 必须展示验证证据，不能只声明完成。</li><li>实现者和审查者尽量使用独立上下文。</li></ol><h2 id="内容晋升" tabindex="-1">内容晋升 <a class="header-anchor" href="#内容晋升" aria-label="Permalink to &quot;内容晋升&quot;">​</a></h2><p>工具指南可能随产品版本变化，因此默认是 <code>Draft</code>。当某项做法：</p><ul><li>在两个以上工具中成立；</li><li>已被至少一个真实项目验证；</li><li>不依赖特定命令或产品界面；</li></ul><p>应将其晋升到 <code>principles/</code>、<code>patterns/</code> 或 <code>playbooks/</code>，工具页只保留对应入口和差异。</p><h2 id="维护规则" tabindex="-1">维护规则 <a class="header-anchor" href="#维护规则" aria-label="Permalink to &quot;维护规则&quot;">​</a></h2><ul><li>优先引用官方文档，不复制大段产品说明。</li><li>标明最后核对日期。</li><li>不在示例中放入真实 Token、租户 ID、用户 ID 或本机路径。</li><li>产品行为变化后，先修工具页，再评估是否影响通用实践。</li></ul>',13)])])}const f=a(d,[["render",o]]);export{p as __pageData,f as default};
